import json
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

# Connect to the Cloud SQL instance using the connection string
conn = pymysql.connect(host='<HOST>', user='<USER>', password='<PASSWORD>', db='<DB_NAME>')
cur = conn.cursor()

@app.route('/search', methods=['GET'])
def search():
    # Get the search parameters from the HTTP request
    query = request.args.get('query')
    category = request.args.get('category')

    # Build a dynamic SQL query using string concatenation
    sql = f"SELECT * FROM products WHERE name LIKE '%{query}%' AND category='{category}'"

    # Execute the SQL query and get the results as a list of dictionaries
    cur.execute(sql)
    results = cur.fetchall()

    # Convert the list of dictionaries to JSON format
    json_results = json.dumps(results)

    return jsonify(json_results)

if __name__ == '__main__':
    app.run(debug=True)